PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?provinceCapital ?capitalLabel
WHERE {
  ?site wdt:P31 wd:Q1270468 ;
         wdt:P31 wd:Q852056 ;
         wdt:P17 wd:Q662 ;
         wdt:P131 ?province .
  ?province wdt:P36 ?provinceCapital .
  ?provinceCapital rdfs:label ?capitalLabel .
  FILTER (LANG(?capitalLabel) = "en")
}
LIMIT 1

